describe("setSessionCustomName", () => {
	it("stores a trimmed custom name", () => {
		const tab = initialTab();
		useSessionStore.getState().setSessionCustomName(tab.id, "  My tab  ");
		expect(
			useSessionStore
				.getState()
				.workspaces[0].sessions.find((s) => s.id === tab.id)!
				.customName,
		).toBe("My tab");
	});

	it("clears customName for null, empty string, or whitespace-only", () => {
		const tab = initialTab();
		useSessionStore.getState().setSessionCustomName(tab.id, "Named");
		useSessionStore.getState().setSessionCustomName(tab.id, "");
		expect(
			useSessionStore
				.getState()
				.workspaces[0].sessions.find((s) => s.id === tab.id)!
				.customName,
		).toBeNull();

		useSessionStore.getState().setSessionCustomName(tab.id, "N2");
		useSessionStore.getState().setSessionCustomName(tab.id, "   ");
		expect(
			useSessionStore
				.getState()
				.workspaces[0].sessions.find((s) => s.id === tab.id)!
				.customName,
		).toBeNull();

		useSessionStore.getState().setSessionCustomName(tab.id, "N3");
		useSessionStore.getState().setSessionCustomName(tab.id, null);
		expect(
			useSessionStore
				.getState()
				.workspaces[0].sessions.find((s) => s.id === tab.id)!
				.customName,
		).toBeNull();
	});

	it("does not change workspaces when sessionId is unknown", () => {
		const before = useSessionStore.getState();
		useSessionStore
			.getState()
			.setSessionCustomName(UNKNOWN_SESSION_ID, "ghost");
		expect(useSessionStore.getState().workspaces).toBe(before.workspaces);
	});
});

