describe("setCurrentTool", () => {
	it("updates currentTool on the matching session", () => {
		const tab = initialTab();
		useSessionStore.getState().setCurrentTool(tab.id, "Reading foo.ts");
		expect(
			useSessionStore
				.getState()
				.workspaces[0].sessions.find((s) => s.id === tab.id)!
				.currentTool,
		).toBe("Reading foo.ts");
	});

	it("clears currentTool when set to null", () => {
		const tab = initialTab();
		useSessionStore.getState().setCurrentTool(tab.id, "t");
		useSessionStore.getState().setCurrentTool(tab.id, null);
		expect(
			useSessionStore
				.getState()
				.workspaces[0].sessions.find((s) => s.id === tab.id)!
				.currentTool,
		).toBeNull();
	});

	it("does not change workspaces when sessionId is unknown", () => {
		const before = useSessionStore.getState();
		useSessionStore.getState().setCurrentTool(UNKNOWN_SESSION_ID, "x");
		expect(useSessionStore.getState().workspaces).toBe(before.workspaces);
	});
});

describe("setLastTurnUsage", () => {
	it("sets lastTurnUsage and copies cumulativeUsage when there was no prior cumulative", () => {
		const tab = initialTab();
		const usage = {
			inputTokens: 10,
			outputTokens: 4,
			cacheRead: 2,
			cacheWrite: 1,
		};
		useSessionStore.getState().setLastTurnUsage(tab.id, usage);
		const sess = useSessionStore
			.getState()
			.workspaces[0].sessions.find((s) => s.id === tab.id)!;
		expect(sess.lastTurnUsage).toEqual(usage);
		expect(sess.cumulativeUsage).toEqual(usage);
	});

	it("adds onto cumulativeUsage on subsequent turns", () => {
		const tab = initialTab();
		const first = {
			inputTokens: 10,
			outputTokens: 5,
			cacheRead: 1,
			cacheWrite: 2,
		};
		const second = {
			inputTokens: 3,
			outputTokens: 1,
			cacheRead: 4,
			cacheWrite: 0,
		};
		useSessionStore.getState().setLastTurnUsage(tab.id, first);
		useSessionStore.getState().setLastTurnUsage(tab.id, second);
		const sess = useSessionStore
			.getState()
			.workspaces[0].sessions.find((s) => s.id === tab.id)!;
		expect(sess.lastTurnUsage).toEqual(second);
		expect(sess.cumulativeUsage).toEqual({
			inputTokens: 13,
			outputTokens: 6,
			cacheRead: 5,
			cacheWrite: 2,
		});
	});

	it("clears lastTurnUsage when set to null without resetting cumulativeUsage", () => {
		const tab = initialTab();
		const usage = {
			inputTokens: 1,
			outputTokens: 1,
			cacheRead: 0,
			cacheWrite: 0,
		};
		useSessionStore.getState().setLastTurnUsage(tab.id, usage);
		useSessionStore.getState().setLastTurnUsage(tab.id, null);
		const sess = useSessionStore
			.getState()
			.workspaces[0].sessions.find((s) => s.id === tab.id)!;
		expect(sess.lastTurnUsage).toBeNull();
		expect(sess.cumulativeUsage).toEqual(usage);
	});

	it("does not change state when sessionId is unknown", () => {
		const before = useSessionStore.getState();
		useSessionStore.getState().setLastTurnUsage(UNKNOWN_SESSION_ID, {
			inputTokens: 1,
			outputTokens: 0,
			cacheRead: 0,
			cacheWrite: 0,
		});
		const after = useSessionStore.getState();
		// the workspaces REFERENCE is the same
		expect(after.workspaces).toBe(before.workspaces);
	});
});

describe("setWorkspaceCustomName", () => {
	it("stores a trimmed workspace custom name", () => {
		const ws = useSessionStore.getState().workspaces[0];
		useSessionStore
			.getState()
			.setWorkspaceCustomName(ws.id, "  Side project  ");
		expect(
			useSessionStore.getState().workspaces.find((w) => w.id === ws.id)!
				.customName,
		).toBe("Side project");
	});

	it("clears customName for null, empty string, or whitespace-only", () => {
		const ws = useSessionStore.getState().workspaces[0];
		useSessionStore.getState().setWorkspaceCustomName(ws.id, "Named");
		useSessionStore.getState().setWorkspaceCustomName(ws.id, "");
		expect(
			useSessionStore.getState().workspaces.find((w) => w.id === ws.id)!
				.customName,
		).toBeNull();

		useSessionStore.getState().setWorkspaceCustomName(ws.id, "N2");
		useSessionStore.getState().setWorkspaceCustomName(ws.id, "   ");
		expect(
			useSessionStore.getState().workspaces.find((w) => w.id === ws.id)!
				.customName,
		).toBeNull();

		useSessionStore.getState().setWorkspaceCustomName(ws.id, "N3");
		useSessionStore.getState().setWorkspaceCustomName(ws.id, null);
		expect(
			useSessionStore.getState().workspaces.find((w) => w.id === ws.id)!
				.customName,
		).toBeNull();
	});

	it("does not change any workspace customName when workspaceId is unknown", () => {
		useSessionStore.getState().createWorkspace();
		const before = useSessionStore.getState();
		const namesBefore = before.workspaces.map((w) => w.customName);

		useSessionStore
			.getState()
			.setWorkspaceCustomName(UNKNOWN_WORKSPACE_ID, "ghost");

		const after = useSessionStore.getState();
		expect(after.workspaces.map((w) => w.customName)).toEqual(namesBefore);
	});
});
